{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI 테마 패키지 릴리스 준비 상태",
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 스모크 테스트가 통과할 경우 금요일 15:00 KST로 한다.",
        "confidence": "confirmed"
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다.",
        "confidence": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 바꾸자.",
        "status": "rejected"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표로만 언급됨, 최종 결정 아님"
      },
      {
        "goal": "README 설치 절차를 가능하면 목요일까지 검토",
        "status": "희망 사항으로 언급됨, 소유자 미지정"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 검토 담당자",
        "status": "미결정"
      },
      {
        "item": "Hara의 tarball 경로 확인 마감 시각",
        "status": "미결정"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있음."
      },
      {
        "risk": "README 설치 절차가 오래되면 릴리스 노트가 사용자에게 오해를 줄 수 있음."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 명시해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 triage 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "pending",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": "다음에는 스모크 테스트 결과, tarball 경로, README 설치 절차 상태, 최종 승인 권한을 확인하면 된다. customer, budget, security incident, production outage, legal approval requirement, 또는 다른 소유자와 마감 시각은 이 회의 메모에 없으므로 새로 만들지 말아야 한다.",
  "non_invention_rules": [
    "고객명은 만들지 않는다.",
    "예산 정보는 만들지 않는다.",
    "보안 사고는 만들지 않는다.",
    "프로덕션 장애는 만들지 않는다.",
    "법무 승인 요구는 만들지 않는다.",
    "소유자가 명시되지 않은 항목에 임의의 소유자를 붙이지 않는다.",
    "명시되지 않은 마감 시각을 임의로 추가하지 않는다.",
    "결정되지 않은 사항을 확정된 결정처럼 쓰지 않는다."
  ]
}
